,p_prompt=>'Payer'
,p_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'if :P4_EXPENSE_ID is not null',
'Then',
'    Begin',
'        select',
'            lender_user_id',
'        into',
'            :P4_PAYER',
'        from',
'            amount_detail',
'        where ',
'            expense_id = :P4_EXPENSE_ID',
'         and group_id = :P4_GROUP_ID',
'         and rownum = 1;',
'        return :P4_PAYER;',
'    Exception',
'        when no_data_found then',
'            return null;',
'     end;',
'end if;',
'return null;'))
,p_source_type=>'FUNCTION_BODY'
,p_source_language=>'PLSQL'
