,p_process_name=>'insert in amount_detail table'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare ',
'    v_selected apex_t_varchar2;',
'    v_count number;',
'Begin',
'   v_selected := apex_string.split(:P4_INCLUDED_MEMBERS,'':'');',
'   v_count := v_selected.count;',
'   for i in 1..v_selected.count loop',
'    insert into amount_detail(',
'            group_id,',
'            expense_id,',
'            borrower_user_id,',
'            borrow_amount,',
'            lender_user_id,',
'            lending_amount',
'    ) VALUES(',
'        :P4_GROUP_ID,',
'        :P4_EXPENSE_ID,',
'        v_selected(i),',
'        :P4_EXPENSE_AMOUNT/v_count,',
'        :P4_PAYER,',
'        :P4_EXPENSE_AMOUNT/v_count',
'    );',
'    END LOOP;',
'END;'))
,p_process_clob_language=>'PLSQL'
,p_process_error_message=>'error'
,p_error_display_location=>'INLINE_IN_NOTIFICATION'
,p_process_when_button_id=>wwv_flow_imp.id(154787842431705757484)
