,p_process_type=>'NATIVE_PLSQL'
,p_process_name=>'update the expense'
,p_process_sql_clob=>wwv_flow_string.join(wwv_flow_t_varchar2(
'declare',
'    v_select_member apex_t_varchar2;',
'    v_count number;',
'Begin',
'    update expense ',
'        set',
'            expense_name = :P4_EXPENSE_NAME,',
'            expense_type = :P4_EXPENSE_TYPE,',
'            expense_amount = :P4_EXPENSE_AMOUNT,',
'            transcation_date = :P4_TRANSCATION_DATE,',
'            note = :P4_NOTE',
'        where',
'            expense_id = :P4_EXPENSE_ID;',
'    ',
'    v_select_member := apex_string.split(:P4_INCLUDED_MEMBERS,'':'');',
'        delete from amount_detail',
'            where expense_id = :P4_EXPENSE_ID;',
'',
'     v_count := v_select_member.count;',
'    for i in 1..v_select_member.count loop',
'        insert into amount_detail(',
'            group_id,',
'            expense_id,',
'            borrower_user_id,',
'            borrow_amount,',
'            lender_user_id,',
'            lending_amount',
'         ) VALUES(',
'        :P4_GROUP_ID,',
'        :P4_EXPENSE_ID,',
'        v_select_member(i),',
'        :P4_EXPENSE_AMOUNT/v_count,',
'        :P4_PAYER,',
'        :P4_EXPENSE_AMOUNT/v_count',
'        );',
'    end loop;',
'end;',
'',
'    ',
''))
,p_process_clob_language=>'PLSQL'
