wwv_flow_imp_page.create_page_plug(
 p_id=>wwv_flow_imp.id(154784943035625212047)
,p_plug_name=>'Balance'
,p_title=>'Balance'
,p_region_template_options=>'#DEFAULT#:t-Region--scrollBody'
,p_plug_template=>4072358936313175081
,p_plug_display_sequence=>10
,p_location=>null
,p_function_body_language=>'PLSQL'
,p_plug_source=>wwv_flow_string.join(wwv_flow_t_varchar2(
'--------------------------------Balances---------------------------------------',
'DECLARE',
'    l_prompt_1            VARCHAR2(20);',
'    l_prompt_2            VARCHAR2(20);',
'    l_prompt_3            VARCHAR2(20);',
'    l_prompt_4            VARCHAR2(20);',
'    l_prompt_5            VARCHAR2(20);',
'    l_individual_amount   NUMBER(12,2);',
'    l_shared_amount       NUMBER(12,2);',
'	l_clob				  Clob := EMPTY_CLOB();',
'---Individual Balance',
'    CURSOR c_individual_balance IS',
'        SELECT',
'            borrower_user_id AS user_id,',
'            ( lending_amount - borrow_amount ) AS amount',
'        FROM',
'            (',
'                SELECT borrower_user_id,SUM(borrow_amount) AS borrow_amount',
'                FROM amount_detail',
'                WHERE group_id =:p8_group_id',
'                    AND borrower_user_id <> lender_user_id',
'                    AND lender_user_id IN (SELECT user_id FROM user_group WHERE group_id =:p8_group_id )',
'                GROUP BY borrower_user_id',
'				',
'                UNION',
'				',
'                SELECT user_id AS borrower_user_id,0 AS borrow_amount',
'                FROM user_group',
'                WHERE user_id NOT IN ( SELECT borrower_user_id FROM amount_detail WHERE group_id =:p8_group_id AND  borrower_user_id <> lender_user_id',
'                                AND borrower_user_id IN ( SELECT user_id FROM user_group WHERE group_id =:p8_group_id))',
'                    AND group_id =:p8_group_id',
'            ),',
'            (',
'                SELECT lender_user_id, SUM(lending_amount) AS lending_amount',
'                FROM amount_detail',
'                WHERE group_id =:p8_group_id',
'                    AND lender_user_id <> borrower_user_id',
'                    AND borrower_user_id IN ( SELECT user_id FROM user_group WHERE group_id =:p8_group_id )',
'                GROUP BY lender_user_id',
'				',
'                UNION',
'				',
'                SELECT user_id AS lender_user_id, 0 AS lending_amount',
'                FROM user_group',
'                WHERE user_id NOT IN ( SELECT lender_user_id',
'                            FROM amount_detail',
'                            WHERE group_id =:p8_group_id',
'                                AND lender_user_id <> borrower_user_id',
'                                AND lender_user_id IN ( SELECT user_id FROM user_group',
'                                        WHERE group_id =:p8_group_id )',
'                        )  AND group_id =:p8_group_id',
'            ) WHERE borrower_user_id = lender_user_id;',
'',
'---Shared Balance',
'',
'    CURSOR c_shared_balance ( p_user_id NUMBER ) IS',
'        SELECT',
'            b.borrower_user_id AS user_id_1,',
'            ( l.lending_amount - b.borrow_amount ) AS amount,',
'            b.lender_user_id AS user_id_2',
'			 FROM ',
'		(SELECT borrower_user_id, SUM(borrow_amount) AS borrow_amount, lender_user_id',
'                FROM amount_detail',
'                WHERE  group_id =:p8_group_id',
'					AND borrower_user_id <> lender_user_id',
'                    AND lender_user_id IN ( SELECT user_id FROM user_group WHERE group_id =:p8_group_id )',
'                GROUP BY borrower_user_id, lender_user_id',
'				',
'                UNION',
'				',
'                SELECT b.user_id AS borrower_user_id,',
'                    0 AS borrow_amount,',
'                    l.user_id AS lender_user_id',
'                FROM',
'                    user_group b,',
'                    user_group l',
'                WHERE  b.user_id <> l.user_id',
'                    AND b.group_id =:p8_group_id',
'                    AND l.group_id =:p8_group_id',
'                    AND b.user_id NOT IN ( SELECT borrower_user_id FROM amount_detail',
'                            WHERE group_id =:p8_group_id',
'                                AND borrower_user_id <> lender_user_id',
'                                AND borrower_user_id IN ( SELECT user_id FROM user_group WHERE group_id =:p8_group_id )',
'                        )',
'                UNION',
'				',
'                SELECT',
'                    b.user_id AS borrower_user_id,',
'                    0 AS borrow_amount,',
'                    l.user_id AS lender_user_id',
'                FROM',
'                    user_group b, user_group l',
'                WHERE  b.user_id <> l.user_id',
'                    AND  b.group_id =:p8_group_id',
'                    AND l.group_id =:p8_group_id',
'                    AND  b.group_id =:p8_group_id',
'                    AND l.user_id NOT IN ( SELECT lender_user_id FROM amount_detail WHERE   group_id =:p8_group_id AND borrower_user_id <> lender_user_id',
'											AND borrower_user_id IN ( SELECT user_id FROM user_group WHERE group_id =:p8_group_id)',
'											)',
'            ) b,',
'            (',
'                SELECT',
'                    lender_user_id,',
'                    SUM(lending_amount) AS lending_amount,',
'                    borrower_user_id',
'                FROM amount_detail',
'                WHERE group_id =:p8_group_id',
'                    AND lender_user_id <> borrower_user_id',
'                    AND borrower_user_id IN (SELECT user_id FROM user_group WHERE  group_id =:p8_group_id )',
'                GROUP BY',
'                    lender_user_id, borrower_user_id',
'                ',
'				UNION',
'                ',
'				SELECT',
'                    l.user_id AS lender_user_id,',
'                    0 AS lending_amount,',
'                    b.user_id AS borrower_user_id',
'                FROM',
'                    user_group l,',
'                    user_group b',
'                WHERE  l.user_id <> b.user_id',
'                    AND l.group_id =:p8_group_id',
'                    AND  b.group_id =:p8_group_id',
'                    AND l.user_id NOT IN ( SELECT lender_user_id FROM  amount_detail WHERE   group_id =:p8_group_id AND  lender_user_id <> borrower_user_id',
'											AND lender_user_id IN ( SELECT user_id FROM user_group  WHERE  group_id =:p8_group_id)  )',
'                UNION',
'                ',
'				SELECT',
'                    l.user_id AS lender_user_id,',
'                    0 AS lending_amount,',
'                    b.user_id AS borrower_user_idborrower_user_id',
'                FROM',
'                    user_group l,',
'                    user_group b',
'                WHERE l.user_id <> b.user_id',
'                    AND l.group_id =:p8_group_id',
'                    AND b.user_id NOT IN (SELECT borrower_user_id FROM amount_detail',
'                            WHERE  group_id =:p8_group_id',
'                                AND   lender_user_id <> borrower_user_id',
'                                AND lender_user_id IN (   SELECT  user_id FROM user_group  WHERE group_id =:p8_group_id ) )',
'            ) l',
'        WHERE   b.lender_user_id = l.borrower_user_id',
'            AND  b.borrower_user_id = l.lender_user_id',
'            AND b.borrower_user_id = p_user_id;',
'',
'BEGIN',
'    FOR r_individual_balance IN c_individual_balance LOOP',
'        IF',
'            r_individual_balance.amount > 0',
'        THEN',
'            l_prompt_1 := '' gets back '';',
'        ELSIF r_individual_balance.amount < 0 THEN',
'            l_prompt_1 := '' owes '';',
'        ELSE',
'            l_prompt_1 := '''';',
'        END IF;',
'',
'        IF',
'            r_individual_balance.amount <> 0',
'        THEN',
'            l_prompt_2 := '' in total'';',
'        ELSE',
'            l_prompt_2 := '' is settled up'';',
'        END IF;',
'',
'        IF',
'            r_individual_balance.amount <> 0',
'        THEN',
'            l_individual_amount := abs(r_individual_balance.amount);',
'        ELSE',
'            l_individual_amount := '''';',
'        END IF;',
'',
'       l_clob := l_clob || ''<button type ="button" class="accordion"><strong>''',
'         || get_user_name(r_individual_balance.user_id)',
'         || ''</strong>''',
'         || l_prompt_1',
'         || ''<strong>''',
'         || l_individual_amount',
'         || ''</strong>''',
'         || l_prompt_2',
'         || ''</button>'';',
'',
'        l_clob := l_clob || ''<ul class="panel ul-sql">'';',
'        FOR r_shared_balance IN c_shared_balance(r_individual_balance.user_id) LOOP',
'            IF',
'                r_shared_balance.amount > 0',
'            THEN',
'                l_prompt_3 := '' gets back '';',
'            ELSIF r_shared_balance.amount < 0 THEN',
'                l_prompt_3 := '' owes '';',
'            ELSE',
'                l_prompt_3 := '''';',
'            END IF;',
'',
'            IF',
'                r_shared_balance.amount > 0',
'            THEN',
'                l_prompt_4 := '' from '';',
'            ELSIF r_shared_balance.amount < 0 THEN',
'                l_prompt_4 := '' to '';',
'            ELSE',
'                l_prompt_4 := '''';',
'            END IF;',
'',
'            IF',
'                r_shared_balance.amount <> 0',
'            THEN',
'                l_prompt_5 := '' in total'';',
'            ELSE',
'                l_prompt_5 := '' is settled up'';',
'            END IF;',
'',
'            IF',
'                r_shared_balance.amount <> 0',
'            THEN',
'                l_shared_amount := abs(r_shared_balance.amount);',
'            ELSE',
'                l_shared_amount := '''';',
'            END IF;',
'',
'            IF',
'                l_shared_amount IS NOT NULL',
'            THEN',
'               l_clob := l_clob || ''<li class="li-sql"><strong>''',
'                 || get_user_name(r_shared_balance.user_id_1)',
'                 || ''</strong>''',
'                 || l_prompt_3',
'                 || ''<strong>''',
'                 || l_shared_amount',
'                 || ''</strong>''',
'                 || l_prompt_4',
'                 || ''<strong>''',
'                 || get_user_name(r_shared_balance.user_id_2)',
'                 || ''</strong>''',
'                 || l_prompt_5',
'                 || ''</li>'';',
'            END IF;',
'',
'        END LOOP;',
'',
'        l_clob := l_clob || ''</ul>'';',
'    END LOOP;',
'	return l_clob;',
'END;'))
,p_lazy_loading=>false
,p_plug_source_type=>'NATIVE_DYNAMIC_CONTENT'
,p_created_on=>wwv_flow_imp.dz('20260408021250Z')
,p_updated_on=>wwv_flow_imp.dz('20260408040647Z')
,p_created_by=>'APRATAPSINGH.1811@GMAIL.COM'
,p_updated_by=>'APRATAPSINGH.1811@GMAIL.COM'
);
wwv_flow_imp_page.create_page_item(
 p_id=>wwv_flow_imp.id(154784943102651212048)
