'        case',
'            when e.expense_type = ''https://icons.iconarchive.com/icons/aha-soft/desktop-buffet/16/Steak-icon.png'' THEN ''Food and Drink''',
'            when e.expense_type = ''https://icons.iconarchive.com/icons/apathae/chakram-2/16/Home-icon.png'' then ''Home and Utilities''',
'            when e.expense_type = ''https://icons.iconarchive.com/icons/iconshow/transport/16/Sportscar-car-icon.png'' THEN ''Transportation''',
'            when e.expense_type = ''https://icons.iconarchive.com/icons/wwalczyszyn/android-style-honeycomb/16/Music-icon.png'' THEN ''Entertainment''',
'            when e.expense_type = ''https://icons.iconarchive.com/icons/awicons/vista-artistic/16/coin-add-icon.png'' THEN ''Other''',
'        end as expense_type',
'    from',
'        amount_detail a,',
'        expense e',
'    where',
'        e.expense_id = a.expense_id',
'    and',
'        a.borrower_user_id = (select user_id from user_detail where user_name = :app_user)',
'    group by',
'        e.expense_type,',
'        a.borrower_user_id;'))
,p_series_type=>'pie'
,p_items_value_column_name=>'AMOUNT'
,p_group_short_desc_column_name=>'EXPENSE_TYPE'
,p_items_label_column_name=>'EXPENSE_TYPE'
,p_items_label_rendered=>true
,p_items_label_position=>'auto'
,p_items_label_display_as=>'LABEL'
,p_gantt_start_date_source=>'DB_COLUMN'
,p_gantt_end_date_source=>'DB_COLUMN'
,p_threshold_display=>'onIndicator'
,p_created_on=>wwv_flow_imp.dz('20260409025806Z')
,p_updated_on=>wwv_flow_imp.dz('20260409025806Z')
,p_created_by=>'APRATAPSINGH.1811@GMAIL.COM'
